components.OverdueDashboard:
{`
import { useState, useEffect } from "react";

const INVOICES = [
  { id: "INV-2401", client: "Acorn Ventures", due: "2024-11-15", amount: 8400, days: 94, status: "Critical" },
  { id: "INV-2389", client: "Birch & Co.", due: "2024-12-01", amount: 12750, days: 78, status: "Critical" },
  { id: "INV-2412", client: "Cedar Solutions", due: "2024-12-18", amount: 3200, days: 61, status: "Critical" },
  { id: "INV-2435", client: "Dune Analytics", due: "2025-01-05", amount: 6800, days: 44, status: "Overdue" },
  { id: "INV-2448", client: "Elm Digital", due: "2025-01-14", amount: 5170, days: 35, status: "Overdue" },
  { id: "INV-2461", client: "Fern Studio", due: "2025-01-28", amount: 4200, days: 21, status: "Past Due" },
  { id: "INV-2477", client: "Grove Media", due: "2025-02-06", amount: 5100, days: 12, status: "Past Due" },
  { id: "INV-2490", client: "Harbor Tech", due: "2025-02-14", amount: 2700, days: 4, status: "Past Due" },
];

const MONTHLY = [
  { month: "Sep", revenue: 68000, overdue: 4200 },
  { month: "Oct", revenue: 74500, overdue: 7800 },
  { month: "Nov", revenue: 61200, overdue: 12400 },
  { month: "Dec", revenue: 55800, overdue: 18900 },
  { month: "Jan", revenue: 70300, overdue: 31200 },
  { month: "Feb", revenue: 63100, overdue: 48320 },
];

const SPARKLINE_DATA = MONTHLY.map(m => m.overdue);

function formatCurrency(n: number) {
  return "$" + n.toLocaleString("en-US", { minimumFractionDigits: 0 });
}

function formatDate(d: string) {
  return new Date(d).toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" });
}

function DaysCell({ days }: { days: number }) {
  let bg = "#FEF9C3", color = "#854D0E";
  if (days > 60) { bg = "#FEE2E2"; color = "#991B1B"; }
  else if (days > 30) { bg = "#FFEDD5"; color = "#9A3412"; }
  return (
    <span style={{
      display: "inline-block",
      padding: "2px 10px",
      borderRadius: 20,
      background: bg,
      color,
      fontWeight: 600,
      fontSize: 13,
    }}>{days}d</span>
  );
}

function StatusBadge({ status }: { status: string }) {
  const map: Record<string, { bg: string; color: string }> = {
    Critical: { bg: "#FEE2E2", color: "#991B1B" },
    Overdue: { bg: "#FFEDD5", color: "#9A3412" },
    "Past Due": { bg: "#FEF9C3", color: "#854D0E" },
  };
  const s = map[status] || { bg: "#F3F4F6", color: "#374151" };
  return (
    <span style={{
      display: "inline-block",
      padding: "3px 10px",
      borderRadius: 20,
      background: s.bg,
      color: s.color,
      fontWeight: 600,
      fontSize: 12,
      letterSpacing: "0.02em",
    }}>{status}</span>
  );
}

function BarChart() {
  const maxVal = Math.max(...MONTHLY.map(m => m.revenue));
  const chartH = 160;
  const chartW = 480;
  const barW = 28;
  const gap = 52;
  const padL = 48;
  const padB = 32;

  return (
    <svg width="100%" viewBox={`0 0 ${chartW} ${chartH + padB}`} style={{ overflow: "visible", display: "block" }}>
      {[0, 0.25, 0.5, 0.75, 1].map((t, i) => {
        const y = chartH - t * chartH;
        return (
          <g key={i}>
            <line x1={padL} x2={chartW} y1={y} y2={y} stroke="#E2E1DE" strokeWidth={1} strokeDasharray="4 3" />
            <text x={padL - 6} y={y + 4} textAnchor="end" fontSize={10} fill="#908C85">
              {t === 0 ? "0" : `${Math.round(t * maxVal / 1000)}k`}
            </text>
          </g>
        );
      })}
      {MONTHLY.map((m, i) => {
        const x = padL + i * gap;
        const revH = (m.revenue / maxVal) * chartH;
        const ovH = (m.overdue / maxVal) * chartH;
        return (
          <g key={m.month}>
            <rect
              x={x - barW / 2 - 2}
              y={chartH - revH}
              width={barW / 2 + 1}
              height={revH}
              rx={3}
              fill="#3B82F6"
              opacity={0.85}
            />
            <rect
              x={x + 2}
              y={chartH - ovH}
              width={barW / 2 + 1}
              height={ovH}
              rx={3}
              fill="#EF4444"
              opacity={0.85}
            />
            <text x={x} y={chartH + padB - 6} textAnchor="middle" fontSize={11} fill="#908C85" fontWeight={500}>
              {m.month}
            </text>
          </g>
        );
      })}
      {/* Legend */}
      <rect x={padL} y={chartH + 14} width={10} height={10} rx={2} fill="#3B82F6" opacity={0.85} />
      <text x={padL + 14} y={chartH + 23} fontSize={11} fill="#908C85">Collected</text>
      <rect x={padL + 80} y={chartH + 14} width={10} height={10} rx={2} fill="#EF4444" opacity={0.85} />
      <text x={padL + 94} y={chartH + 23} fontSize={11} fill="#908C85">Overdue</text>
    </svg>
  );
}

function Toast({ visible, onHide }: { visible: boolean; onHide: () => void }) {
  useEffect(() => {
    if (visible) {
      const t = setTimeout(onHide, 4000);
      return () => clearTimeout(t);
    }
  }, [visible]);

  return (
    <div style={{
      position: "fixed",
      bottom: 32,
      left: "50%",
      transform: visible ? "translateX(-50%) translateY(0)" : "translateX(-50%) translateY(120px)",
      opacity: visible ? 1 : 0,
      transition: "transform 0.35s cubic-bezier(0.34,1.56,0.64,1), opacity 0.3s ease",
      background: "#111111",
      color: "#fff",
      padding: "14px 24px",
      borderRadius: 12,
      fontWeight: 600,
      fontSize: 14,
      boxShadow: "0 8px 32px rgba(0,0,0,0.22)",
      zIndex: 9999,
      display: "flex",
      alignItems: "center",
      gap: 10,
      pointerEvents: visible ? "auto" : "none",
    }}>
      <span style={{ fontSize: 18 }}>✓</span>
      Reminders sent to all overdue clients!
    </div>
  );
}

export default function OverdueDashboard() {
  const [toast, setToast] = useState(false);
  const [criticalToast, setCriticalToast] = useState(false);
  const [toastMsg, setToastMsg] = useState("");

  function sendAll() {
    setToastMsg("✓ Reminders sent to all overdue clients!");
    setToast(true);
  }
  function sendCritical() {
    setToastMsg("✓ Reminders sent to Critical clients only!");
    setToast(true);
  }

  return (
    <div style={{
      fontFamily: "system-ui, -apple-system, Segoe UI, Roboto, sans-serif",
      background: "var(--vendo-color-background, #FBFBFA)",
      minHeight: "100vh",
      padding: "0 0 48px 0",
    }}>
      {/* Header */}
      <div style={{
        background: "#111111",
        padding: "28px 32px 24px",
        borderRadius: "0 0 20px 20px",
        marginBottom: 28,
      }}>
        <div style={{ display: "flex", alignItems: "flex-start", justifyContent: "space-between", flexWrap: "wrap", gap: 12 }}>
          <div>
            <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 6 }}>
              <h1 style={{ color: "#fff", fontSize: 24, fontWeight: 700, margin: 0, letterSpacing: "-0.02em" }}>
                Overdue Invoices
              </h1>
              <span style={{
                background: "#EF4444",
                color: "#fff",
                borderRadius: 20,
                padding: "3px 12px",
                fontSize: 13,
                fontWeight: 700,
              }}>7 invoices overdue</span>
            </div>
            <p style={{ color: "#908C85", margin: 0, fontSize: 14 }}>
              Total overdue:{" "}
              <span style={{ color: "#F87171", fontWeight: 700, fontSize: 16 }}>$48,320</span>
              {" "}— Last updated Feb 18, 2025
            </p>
          </div>
          <div style={{ display: "flex", gap: 10, alignItems: "center" }}>
            <button
              onClick={sendCritical}
              style={{
                background: "transparent",
                border: "1.5px solid #EF4444",
                color: "#F87171",
                borderRadius: 10,
                padding: "10px 18px",
                fontWeight: 600,
                fontSize: 14,
                cursor: "pointer",
                transition: "background 0.2s",
                fontFamily: "inherit",
              }}
              onMouseEnter={e => (e.currentTarget.style.background = "rgba(239,68,68,0.1)")}
              onMouseLeave={e => (e.currentTarget.style.background = "transparent")}
            >
              Send to Critical Only
            </button>
            <button
              onClick={sendAll}
              style={{
                background: "#EF4444",
                border: "none",
                color: "#fff",
                borderRadius: 10,
                padding: "10px 22px",
                fontWeight: 700,
                fontSize: 14,
                cursor: "pointer",
                boxShadow: "0 4px 14px rgba(239,68,68,0.35)",
                transition: "background 0.2s, transform 0.15s",
                fontFamily: "inherit",
              }}
              onMouseEnter={e => { e.currentTarget.style.background = "#DC2626"; e.currentTarget.style.transform = "scale(1.03)"; }}
              onMouseLeave={e => { e.currentTarget.style.background = "#EF4444"; e.currentTarget.style.transform = "scale(1)"; }}
            >
              📨 Send Reminders
            </button>
          </div>
        </div>
      </div>

      <div style={{ maxWidth: 1100, margin: "0 auto", padding: "0 20px" }}>
        {/* Summary Cards */}
        <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: 16, marginBottom: 24 }}>
          {[
            { label: "Total Overdue", value: "$48,320", sub: "Across 7 invoices", accent: "#EF4444", icon: "⚠️" },
            { label: "Avg Days Overdue", value: "42 days", sub: "Across all invoices", accent: "#F97316", icon: "📅" },
            { label: "Oldest Invoice", value: "94 days", sub: "INV-2401 · Acorn Ventures", accent: "#DC2626", icon: "🔴" },
          ].map(card => (
            <div key={card.label} style={{
              background: "#fff",
              borderRadius: 14,
              padding: "20px 22px",
              boxShadow: "0 1px 4px rgba(0,0,0,0.07), 0 4px 16px rgba(0,0,0,0.05)",
              border: "1px solid #E2E1DE",
            }}>
              <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 8 }}>
                <span style={{ fontSize: 18 }}>{card.icon}</span>
                <span style={{ fontSize: 13, color: "#908C85", fontWeight: 500 }}>{card.label}</span>
              </div>
              <div style={{ fontSize: 28, fontWeight: 800, color: card.accent, letterSpacing: "-0.03em", lineHeight: 1.1 }}>
                {card.value}
              </div>
              <div style={{ fontSize: 12, color: "#908C85", marginTop: 6 }}>{card.sub}</div>
            </div>
          ))}
        </div>

        {/* Charts Row */}
        <div style={{ display: "grid", gridTemplateColumns: "1fr 320px", gap: 16, marginBottom: 24 }}>
          {/* Bar Chart */}
          <div style={{
            background: "#fff",
            borderRadius: 14,
            padding: "22px 24px",
            boxShadow: "0 1px 4px rgba(0,0,0,0.07), 0 4px 16px rgba(0,0,0,0.05)",
            border: "1px solid #E2E1DE",
          }}>
            <div style={{ marginBottom: 16 }}>
              <div style={{ fontWeight: 700, fontSize: 15, color: "#111", marginBottom: 2 }}>Revenue vs. Overdue</div>
              <div style={{ fontSize: 12, color: "#908C85" }}>Monthly comparison · Last 6 months</div>
            </div>
            <BarChart />
          </div>

          {/* Sparkline Card */}
          <div style={{
            background: "#fff",
            borderRadius: 14,
            padding: "22px 24px",
            boxShadow: "0 1px 4px rgba(0,0,0,0.07), 0 4px 16px rgba(0,0,0,0.05)",
            border: "1px solid #E2E1DE",
            display: "flex",
            flexDirection: "column",
          }}>
            <div style={{ marginBottom: 12 }}>
              <div style={{ fontWeight: 700, fontSize: 15, color: "#111", marginBottom: 2 }}>Overdue Trend</div>
              <div style={{ fontSize: 12, color: "#908C85" }}>Balance growth over 6 months</div>
            </div>
            <div style={{ flex: 1, display: "flex", flexDirection: "column", justifyContent: "center" }}>
              <div style={{ fontSize: 28, fontWeight: 800, color: "#EF4444", letterSpacing: "-0.03em", marginBottom: 12 }}>
                $48,320
              </div>
              <div style={{ fontSize: 12, color: "#EF4444", fontWeight: 600, marginBottom: 16 }}>
                ▲ 55% increase since Sep
              </div>
              {/* MapleSparkline placeholder rendered inline */}
              <div style={{ background: "#FEF2F2", borderRadius: 10, padding: "12px 8px" }}>
                <svg width="100%" height="48" viewBox="0 0 240 48" preserveAspectRatio="none">
                  {(() => {
                    const data = SPARKLINE_DATA;
                    const min = Math.min(...data);
                    const max = Math.max(...data);
                    const pts = data.map((v, i) => {
                      const x = (i / (data.length - 1)) * 240;
                      const y = 44 - ((v - min) / (max - min)) * 40;
                      return \`\${x},\${y}\`;
                    }).join(" ");
                    const areaClose = \` 240,44 0,44\`;
                    return (
                      <>
                        <defs>
                          <linearGradient id="redGrad" x1="0" y1="0" x2="0" y2="1">
                            <stop offset="0%" stopColor="#EF4444" stopOpacity={0.25} />
                            <stop offset="100%" stopColor="#EF4444" stopOpacity={0.02} />
                          </linearGradient>
                        </defs>
                        <polygon points={pts + areaClose} fill="url(#redGrad)" />
                        <polyline points={pts} fill="none" stroke="#EF4444" strokeWidth={2.5} strokeLinecap="round" strokeLinejoin="round" />
                        {data.map((v, i) => {
                          const x = (i / (data.length - 1)) * 240;
                          const y = 44 - ((v - min) / (max - min)) * 40;
                          return <circle key={i} cx={x} cy={y} r={3} fill="#EF4444" />;
                        })}
                      </>
                    );
                  })()}
                </svg>
              </div>
              <div style={{ display: "flex", justifyContent: "space-between", marginTop: 6 }}>
                {MONTHLY.map(m => (
                  <span key={m.month} style={{ fontSize: 10, color: "#908C85" }}>{m.month}</span>
                ))}
              </div>
            </div>
          </div>
        </div>

        {/* Invoice Table */}
        <div style={{
          background: "#fff",
          borderRadius: 14,
          boxShadow: "0 1px 4px rgba(0,0,0,0.07), 0 4px 16px rgba(0,0,0,0.05)",
          border: "1px solid #E2E1DE",
          overflow: "hidden",
        }}>
          <div style={{ padding: "20px 24px 16px", borderBottom: "1px solid #E2E1DE", display: "flex", alignItems: "center", justifyContent: "space-between" }}>
            <div>
              <div style={{ fontWeight: 700, fontSize: 15, color: "#111" }}>Overdue Invoice List</div>
              <div style={{ fontSize: 12, color: "#908C85", marginTop: 2 }}>8 invoices · Sorted by days overdue</div>
            </div>
            <span style={{ background: "#FEE2E2", color: "#991B1B", borderRadius: 20, padding: "4px 14px", fontSize: 13, fontWeight: 700 }}>
              $48,320 total
            </span>
          </div>
          <div style={{ overflowX: "auto" }}>
            <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 14 }}>
              <thead>
                <tr style={{ background: "#FAFAF9" }}>
                  {["Invoice #", "Client", "Due Date", "Amount", "Days Overdue", "Status"].map(h => (
                    <th key={h} style={{
                      padding: "12px 20px",
                      textAlign: "left",
                      fontWeight: 600,
                      fontSize: 12,
                      color: "#908C85",
                      letterSpacing: "0.04em",
                      textTransform: "uppercase",
                      borderBottom: "1px solid #E2E1DE",
                      whiteSpace: "nowrap",
                    }}>{h}</th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {INVOICES.map((inv, i) => (
                  <tr key={inv.id} style={{
                    borderBottom: i < INVOICES.length - 1 ? "1px solid #F3F2F0" : "none",
                    transition: "background 0.15s",
                  }}
                    onMouseEnter={e => (e.currentTarget.style.background = "#FAFAF9")}
                    onMouseLeave={e => (e.currentTarget.style.background = "transparent")}
                  >
                    <td style={{ padding: "14px 20px", fontWeight: 600, color: "#111", fontFamily: "monospace", fontSize: 13 }}>
                      {inv.id}
                    </td>
                    <td style={{ padding: "14px 20px", color: "#111", fontWeight: 500 }}>{inv.client}</td>
                    <td style={{ padding: "14px 20px", color: "#908C85" }}>{formatDate(inv.due)}</td>
                    <td style={{ padding: "14px 20px", fontWeight: 700, color: "#111" }}>{formatCurrency(inv.amount)}</td>
                    <td style={{ padding: "14px 20px" }}><DaysCell days={inv.days} /></td>
                    <td style={{ padding: "14px 20px" }}><StatusBadge status={inv.status} /></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </div>

      {/* Toast */}
      <div style={{
        position: "fixed",
        bottom: 32,
        left: "50%",
        transform: toast ? "translateX(-50%) translateY(0)" : "translateX(-50%) translateY(120px)",
        opacity: toast ? 1 : 0,
        transition: "transform 0.4s cubic-bezier(0.34,1.56,0.64,1), opacity 0.3s ease",
        background: "#111111",
        color: "#fff",
        padding: "14px 28px",
        borderRadius: 14,
        fontWeight: 600,
        fontSize: 14,
        boxShadow: "0 8px 32px rgba(0,0,0,0.22)",
        zIndex: 9999,
        display: "flex",
        alignItems: "center",
        gap: 10,
        pointerEvents: toast ? "auto" : "none",
        whiteSpace: "nowrap",
      }}>
        <span style={{ color: "#4ADE80", fontSize: 18 }}>✓</span>
        {toastMsg}
        <button
          onClick={() => setToast(false)}
          style={{ background: "none", border: "none", color: "#908C85", cursor: "pointer", marginLeft: 8, fontSize: 16, padding: 0, lineHeight: 1 }}
        >×</button>
      </div>

      {/* Auto-hide toast */}
      {toast && (() => { setTimeout(() => setToast(false), 4000); return null; })()}
    </div>
  );
}
`}
